function [nmbTrc,trcLst] = fTrcLstV01(scnDir)%% return number of tracfiles(timingtrace) saved and list of it% Kei Nakamura% Created on Friday, December 18th 2009.% Modified on% nmbTrc: number of traces exist in scnDir% trcLst: trace file list (shot number)% scnDir: directory to look at% nmbSht: number of shots from trex logfilename = ['/*timingtrace*.txt'];trcLst = dir([scnDir,name]);         % information for Scan* file[nmbTrc,dlt] = size(trcLst);   % number of traces
